import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const animateLight = () => {
      const svgDoc = document.getElementById("photoautomat-object")?.contentDocument; // ✅ เข้าถึงเอกสารภายใน <object>
      if (svgDoc) {
        const lightElement = svgDoc.getElementById("light"); // ✅ ดึง element "light"
        if (lightElement) {
          lightElement.style.fill =
            lightElement.style.fill === "rgb(231, 229, 213)" // #e7e5d5
              ? "#ffe966"
              : "#e7e5d5";
        }
      }
    };

    const interval = setInterval(animateLight, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      {/* ✅ ใช้ <object> เพื่อโหลดไฟล์ SVG แบบ inline */}
      <object
        id="photoautomat-object"
        type="image/svg+xml"
        data="/photoautomat.svg"
        className="photoautomat-svg"
      />

      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
    </div>
  );
};

export default Home;
